pub fn particleShaderDesc(backend: sg.Backend) sg.ShaderDesc {
    var desc: sg.ShaderDesc = .{};
    desc.label = "particle_shader";
    switch (backend) {
        .GLES3 => {
            desc.vertex_func.source = &vs_particle_source_glsl300es;
            desc.vertex_func.entry = "main";
            desc.fragment_func.source = &fs_particle_source_glsl300es;
            desc.fragment_func.entry = "main";
            desc.attrs[0].base_type = .FLOAT;
            desc.attrs[0].glsl_name = "quad_corner";
            desc.attrs[1].base_type = .FLOAT;
            desc.attrs[1].glsl_name = "inst_pos";
            desc.attrs[2].base_type = .FLOAT;
            desc.attrs[2].glsl_name = "inst_size";
            desc.attrs[3].base_type = .FLOAT;
            desc.attrs[3].glsl_name = "inst_color";
            desc.attrs[4].base_type = .FLOAT;
            desc.attrs[4].glsl_name = "inst_shape";
            desc.uniform_blocks[0].stage = .VERTEX;
            desc.uniform_blocks[0].layout = .STD140;
            desc.uniform_blocks[0].size = 64;
            desc.uniform_blocks[0].glsl_uniforms[0].type = .FLOAT4;
            desc.uniform_blocks[0].glsl_uniforms[0].array_count = 4;
            desc.uniform_blocks[0].glsl_uniforms[0].glsl_name = "vs_params";
        },
        .METAL_MACOS => {
            desc.vertex_func.source = &vs_particle_source_metal_macos;
            desc.vertex_func.entry = "main0";
            desc.fragment_func.source = &fs_particle_source_metal_macos;
            desc.fragment_func.entry = "main0";
            desc.attrs[0].base_type = .FLOAT;
            desc.attrs[1].base_type = .FLOAT;
            desc.attrs[2].base_type = .FLOAT;
            desc.attrs[3].base_type = .FLOAT;
            desc.attrs[4].base_type = .FLOAT;
            desc.uniform_blocks[0].stage = .VERTEX;
            desc.uniform_blocks[0].layout = .STD140;
            desc.uniform_blocks[0].size = 64;
            desc.uniform_blocks[0].msl_buffer_n = 0;
        },
        .METAL_IOS => {
            desc.vertex_func.source = &vs_particle_source_metal_ios;
            desc.vertex_func.entry = "main0";
            desc.fragment_func.source = &fs_particle_source_metal_ios;
            desc.fragment_func.entry = "main0";
            desc.attrs[0].base_type = .FLOAT;
            desc.attrs[1].base_type = .FLOAT;
            desc.attrs[2].base_type = .FLOAT;
            desc.attrs[3].base_type = .FLOAT;
            desc.attrs[4].base_type = .FLOAT;
            desc.uniform_blocks[0].stage = .VERTEX;
            desc.uniform_blocks[0].layout = .STD140;
            desc.uniform_blocks[0].size = 64;
            desc.uniform_blocks[0].msl_buffer_n = 0;
        },
        else => {},
    }
    return desc;
}
pub fn particleAttrSlot(attr_name: []const u8) ?usize {
    if (std.mem.eql(u8, attr_name, "quad_corner")) {
        return 0;
    }
    if (std.mem.eql(u8, attr_name, "inst_pos")) {
        return 1;
    }
    if (std.mem.eql(u8, attr_name, "inst_size")) {
        return 2;
    }
    if (std.mem.eql(u8, attr_name, "inst_color")) {
        return 3;
    }
    if (std.mem.eql(u8, attr_name, "inst_shape")) {
        return 4;
    }
    return null;
}
pub fn particleTextureSlot(tex_name: []const u8) ?usize {
    _ = tex_name;
    return null;
}
pub fn particleSamplerSlot(smp_name: []const u8) ?usize {
    _ = smp_name;
    return null;
}
pub fn particleUniformBlockSlot(ub_name: []const u8) ?usize {
    if (std.mem.eql(u8, ub_name, "vs_params")) {
        return 0;
    }
    return null;
}
pub fn particleUniformBlockSize(ub_name: []const u8) ?usize {
    if (std.mem.eql(u8, ub_name, "vs_params")) {
        return @sizeOf(VsParams);
    }
    return null;
}
pub fn particleUniformOffset(ub_name: []const u8, u_name: []const u8) ?usize {
    if (std.mem.eql(u8, ub_name, "vs_params")) {
        if (std.mem.eql(u8, u_name, "mvp")) {
            return 0;
        }
    }
    return null;
}
pub fn particleUniformDesc(ub_name: []const u8, u_name: []const u8) ?sg.GlslShaderUniform {
    if (std.mem.eql(u8, ub_name, "vs_params")) {
        if (std.mem.eql(u8, u_name, "mvp")) {
            var desc: sg.GlslShaderUniform = .{};
            desc.type = .MAT4;
            desc.array_count = 0;
            desc.glsl_name = "mvp";
            return desc;
        }
    }
    return null;
}
pub fn particleStorageBufferSlot(sbuf_name: []const u8) ?usize {
    _ = sbuf_name;
    return null;
}
pub fn particleStorageImageSlot(simg_name: []const u8) ?usize {
    _ = simg_name;
    return null;
}
